
/** @jsx jsx */
import * as React from "react"
import {jsx, Heading} from "theme-ui"

const ContentsList = ({ items }) => {
	return (
		<ul sx={{ "a": {color: `secondary`, textDecoration: `none`, ":hover": { color: `heading` } }}}>
			{items.map(item => {
			return <ContentsItem key={`${item.url}-item`} item={item} />
			})}
		</ul>
	)
}

const ContentsItem = ({ item }) => (
	<li>
		<a href={item.url}>{item.title}</a>
		{/**
		* conditionally render another `ContentsList` within this `<li>`
		* if there is a `items` array within this `item`
		*/}
		{item.items && item.items.length && (
		<ContentsList key={`${item.url}-list`} items={item.items} />
		)}
	</li>
)

export const TableOfContents = ({ tableOfContents }) => {
	if (!tableOfContents.items) {
	  return null
	}
	return (
		<div sx={{ position: `sticky`, top:0 }}>
			<Heading as="h4" variant="styles.h4">Table of contents</Heading>
			<ContentsList items={tableOfContents.items}/>
		</div>
	)
}

export default TableOfContents