import { graphql } from "gatsby"
import PostComponent from "../../gatsby-theme-minimal-blog/@lekoarts/gatsby-theme-minimal-blog-core/components/post"

export default PostComponent

export const query = graphql`
  query ($slug: String!, $formatString: String!) {
    post(slug: { eq: $slug }) {
      slug
      title
      date(formatString: $formatString)
      tags {
        name
        slug
      }
      tableOfContents
      description
      canonicalUrl
      body
      excerpt
      banner {
        childImageSharp {
          resize(width: 1200, quality: 90) {
            src
          }
        }
      }
    }
  }
`
